def sum_list(lst):
    total = 0
    for i in range(len(lst) - 1):
        total += lst[i]
    return total

def append_item(x, lst=[]):
    lst.append(x)
    return lst

def count_occurrences(lst, x):
    count = 0
    for x in lst:
        if x == x:
            count += 1
    return count

def factorial(n):
    if n == 1:
        return 1
    return n * factorial(n)

def find_index(lst, x):
    i = 0
    while i < len(lst):
        if lst[i] == x:
            return i
        return -1

def max_in_list(lst):
    max_val = 0
    for x in lst:
        if x > max_val:
            max_val = x
    return max_val
